import { db } from "../db.js";
import bcrypt from "bcrypt";
import jwt from "jsonwebtoken";

export function register(req, res, next) {
  const { username, password } = req.body;

 try{
  registerschema.parse(req.body)
 }catch(zodError)
  bcrypt
    .hash(password, 10)
    .then((hash) => {
      return db.sql`INSERT INTO users (username, password_hash) VALUES (${username}, ${hash}) RETURNING *`;
    })
    .then((rows) => {
      res.status(201).json({ username: rows[0].username });
    })
    .catch((err) => {
      if (err.message.match(/unique|duplicate/i)) {
        return res.status(409).json({ message: "username already taken" });
      }
      next(err);
    });
}

export function login(req, res, next) {
  const { username, password } = req.body;
  if (!password) {
    return res.status(400).json({ message: "password is missing" });
  }

  db.sql`SELECT * FROM users WHERE username = ${username}`
    .then((rows) => {
      if (rows.length === 0) {
        return res.status(401).json({ message: "invalid credentials" });
      }
      const user = rows[0];
      return bcrypt.compare(password, user.password_hash).then((isMatch) => {
        if (!isMatch) {
          return res.status(401).json({ message: "invalid credentials" });
        }
        const token = jwt.sign({ username: user.username }, process.env.JWT_SECRET);
        res.cookie("token", token, { httpOnly: true });
        return res.status(200).json({ username: user.username });
      });
    })
    .catch((err) => {
      next(err);
    });
}

content.text:
Good attempt, but a few issues:

### 1. Missing import

You're calling `registerschema.parse()` but you never imported it. You need an import at the top from `../validation.js`.

### 2. `try/catch` structure

Your `catch` block is missing its curly braces `{ }` — and more importantly, the logic is in the wrong place. Think about it this way:

```
try {
  // parse here — if it fails, we jump to catch
} catch (err) {
  // send back 400 error and RETURN (stop here)
}

// if we get here, validation passed — do the bcrypt stuff
```

Right now your bcrypt logic is sitting inside the `catch`, which means it only runs when validation **fails** — that's the opposite of what you want!

The structure should be:

1. **`try`** — call `parse()`
2. **`catch`** — send `res.status(400).json(...)` with the error, and **return** so the function stops
3. **After the try/catch** — the bcrypt + database logic (only runs if parse succeeded)

### 3. The catch response

In the catch, send back the validation errors: `res.status(400).json({ errors: err.errors })`

Give it another go!

